fn collect_json_files_recursive_inner(
    current: &Utf8Path,
    files: &mut Vec<Utf8PathBuf>,
) -> Result<(), Box<dyn std::error::Error>> {
    for entry in fs::read_dir(current)? {
        let entry = entry?;
        let path = Utf8PathBuf::from_path_buf(entry.path())
            .map_err(|_| "JSON artifact path is not valid utf-8")?;
        let metadata = fs::symlink_metadata(&path)?;
        if metadata.file_type().is_symlink() {
            return Err(format!("JSON artifact contains symlink: {path}").into());
        }
        if metadata.is_dir() {
            collect_json_files_recursive_inner(&path, files)?;
        } else if metadata.is_file()
            && path
                .extension()
                .is_some_and(|extension| extension.eq_ignore_ascii_case("json"))
        {
            files.push(path);
        }
    }
    Ok(())
}

fn collect_evidence_text_files_recursive_inner(
    current: &Utf8Path,
    files: &mut Vec<Utf8PathBuf>,
) -> Result<(), Box<dyn std::error::Error>> {
    for entry in fs::read_dir(current)? {
        let entry = entry?;
        let path = Utf8PathBuf::from_path_buf(entry.path())
            .map_err(|_| "evidence artifact path is not valid utf-8")?;
        let metadata = fs::symlink_metadata(&path)?;
        if metadata.file_type().is_symlink() {
            return Err(format!("evidence artifact contains symlink: {path}").into());
        }
        if metadata.is_dir() {
            collect_evidence_text_files_recursive_inner(&path, files)?;
        } else if metadata.is_file()
            && path.extension().is_some_and(|extension| {
                extension.eq_ignore_ascii_case("log") || extension.eq_ignore_ascii_case("txt")
            })
        {
            files.push(path);
        }
    }
    Ok(())
}

fn collect_rust_files_recursive_inner(
    current: &Utf8Path,
    files: &mut Vec<Utf8PathBuf>,
) -> Result<(), Box<dyn std::error::Error>> {
    for entry in fs::read_dir(current)? {
        let entry = entry?;
        let path = Utf8PathBuf::from_path_buf(entry.path())
            .map_err(|_| "Rust artifact path is not valid utf-8")?;
        let metadata = fs::symlink_metadata(&path)?;
        if metadata.file_type().is_symlink() {
            return Err(format!("Rust artifact contains symlink: {path}").into());
        }
        if metadata.is_dir() {
            collect_rust_files_recursive_inner(&path, files)?;
        } else if metadata.is_file()
            && path
                .extension()
                .is_some_and(|extension| extension.eq_ignore_ascii_case("rs"))
        {
            files.push(path);
        }
    }
    Ok(())
}

fn collect_vst3_bundle_dirs_recursive_inner(
    current: &Utf8Path,
    bundles: &mut Vec<Utf8PathBuf>,
) -> Result<(), Box<dyn std::error::Error>> {
    for entry in fs::read_dir(current)? {
        let entry = entry?;
        let path = Utf8PathBuf::from_path_buf(entry.path())
            .map_err(|_| "evidence artifact path is not valid utf-8")?;
        let metadata = fs::symlink_metadata(&path)?;
        if metadata.file_type().is_symlink() {
            return Err(format!("evidence artifact contains symlink: {path}").into());
        }
        if !metadata.is_dir() {
            continue;
        }
        if path
            .extension()
            .is_some_and(|extension| extension.eq_ignore_ascii_case("vst3"))
        {
            bundles.push(path);
        } else {
            collect_vst3_bundle_dirs_recursive_inner(&path, bundles)?;
        }
    }
    Ok(())
}

fn doctor_artifact_os(path: &Utf8Path) -> Option<&'static str> {
    let name = Utf8Path::new(path.file_name()?);
    os_from_artifact_path_tokens(&artifact_path_tokens(name))
}

fn normalize_doctor_os_label(value: &str) -> Option<&'static str> {
    let normalized = value
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .map(|ch| ch.to_ascii_lowercase())
        .collect::<String>();
    match normalized.as_str() {
        "linux" => Some("Linux"),
        "macos" | "darwin" | "osx" => Some("macOS"),
        "windows" | "win32" | "win64" => Some("Windows"),
        _ => None,
    }
}

fn missing_doctor_checks(os: &str, report: &DoctorReport) -> Vec<String> {
    const OK: &[&str] = &["ok"];
    const OK_OR_UNKNOWN: &[&str] = &["ok", "unknown"];
    const OK_OR_SKIPPED: &[&str] = &["ok", "skipped"];

    let mut required = vec![
        ("rustc", OK),
        ("cargo", OK),
        ("node", OK),
        ("npm", OK),
        ("vst3 binding baseline", OK),
        ("vst3 SDK headers", OK_OR_SKIPPED),
        ("vst3 validator", OK),
        ("system webview", OK),
    ];
    match os {
        "Linux" => required.push(("signing: linux release policy", OK_OR_UNKNOWN)),
        "macOS" => {
            required.push(("signing: codesign", OK));
            required.push(("signing: notarytool", OK));
        }
        "Windows" => required.push(("signing: signtool", OK)),
        _ => {}
    }

    required
        .into_iter()
        .filter_map(|(required, accepted_statuses)| {
            let check = report.checks.iter().find(|check| check.name == required)?;
            (!accepted_statuses.contains(&check.status.as_str()))
                .then(|| format!("{os}/{required} status {}", check.status))
        })
        .chain(
            required_doctor_check_names(os)
                .into_iter()
                .filter(|required| !report.checks.iter().any(|check| check.name == *required))
                .map(|required| format!("{os}/{required} missing")),
        )
        .chain(
            unexpected_doctor_checks_for_os(os, report)
                .into_iter()
                .map(|check| format!("{os}/{check} unexpected for {os} doctor report")),
        )
        .collect()
}

fn required_doctor_check_names(os: &str) -> Vec<&'static str> {
    let mut required = vec![
        "rustc",
        "cargo",
        "node",
        "npm",
        "vst3 binding baseline",
        "vst3 SDK headers",
        "vst3 validator",
        "system webview",
    ];
    match os {
        "Linux" => required.push("signing: linux release policy"),
        "macOS" => {
            required.push("signing: codesign");
            required.push("signing: notarytool");
        }
        "Windows" => required.push("signing: signtool"),
        _ => {}
    }
    required
}

fn validate_signing_evidence(path: &Utf8Path) -> Result<(), Box<dyn std::error::Error>> {
    signing_evidence_platforms(path).map(|_| ())
}

const SIGNING_NOTARIZATION_LOG_MAX_BYTES: usize = 512 * 1024;
const MACOS_CODE_RESOURCES_MAX_BYTES: u64 = 16 * 1024 * 1024;

fn signing_evidence_platforms(
    path: &Utf8Path,
) -> Result<BTreeSet<SigningEvidencePlatform>, Box<dyn std::error::Error>> {
    let metadata = require_existing_file_or_directory_no_symlink("signing evidence path", path)?;
    if metadata.is_dir() {
        if path.extension() == Some("vst3") {
            validate_macos_code_resources(path)?;
            return Ok(BTreeSet::from([SigningEvidencePlatform::Macos]));
        }
        return Err("directory is not a macOS signed .vst3 bundle".into());
    }

    let text = read_text_file_no_symlink("signing evidence path", path)?;
    signing_evidence_platforms_from_text(&text)
}

fn signing_evidence_platforms_from_text(
    text: &str,
) -> Result<BTreeSet<SigningEvidencePlatform>, Box<dyn std::error::Error>> {
    validate_release_evidence_log_text("signing evidence log", text)?;

    let lower = text.to_ascii_lowercase();
    if let Some(reason) = signing_negative_evidence(&lower) {
        return Err(format!("negative signing evidence found: {reason}").into());
    }

    let mut platforms = BTreeSet::new();
    if explicit_truthy_marker(&lower, &["codesign"]) {
        platforms.insert(SigningEvidencePlatform::Macos);
    }
    if explicit_truthy_marker(&lower, &["signtool"]) {
        platforms.insert(SigningEvidencePlatform::Windows);
    }
    let macos_codesign =
        lower.contains("valid on disk") && lower.contains("satisfies its designated requirement");
    if macos_codesign {
        platforms.insert(SigningEvidencePlatform::Macos);
    }
    if lower.contains("successfully verified") {
        platforms.insert(SigningEvidencePlatform::Windows);
    }
    let windows_signtool_summary =
        lower.contains("signtool") && signtool_error_count(&lower) == Some(0);
    if windows_signtool_summary {
        platforms.insert(SigningEvidencePlatform::Windows);
    }
    if platforms.is_empty() {
        Err("no positive signing marker found".into())
    } else {
        Ok(platforms)
    }
}

fn signing_negative_evidence(text: &str) -> Option<String> {
    for line in text.lines() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        if explicit_falsy_marker_line(
            line,
            &["signed", "signing", "signature", "codesign", "signtool"],
        ) {
            return Some(line.to_string());
        }
        if extract_count_near_marker(line, "number of errors").is_some_and(|errors| errors > 0) {
            return Some(line.to_string());
        }
        if line_contains_any(
            line,
            &[
                "signtool error:",
                "sign tool error:",
                "codesign failed",
                "failed to verify",
                "verification failed",
                "signature verification failed",
                "code object is not signed",
                "not signed at all",
                "invalid signature",
                "signature is invalid",
                "sealed resource is missing or invalid",
                "no signature found",
            ],
        ) {
            return Some(line.to_string());
        }
    }
    None
}

fn signtool_error_count(text: &str) -> Option<u32> {
    text.lines()
        .find_map(|line| extract_count_near_marker(line, "number of errors"))
}

fn validate_macos_code_resources(bundle: &Utf8Path) -> Result<(), Box<dyn std::error::Error>> {
    require_existing_directory_no_symlink("macOS bundle Contents", &bundle.join("Contents"))?;
    require_existing_directory_no_symlink(
        "macOS CodeSignature directory",
        &bundle.join("Contents/_CodeSignature"),
    )?;
    let code_resources = bundle.join("Contents/_CodeSignature/CodeResources");
    let metadata = match require_existing_file_no_symlink("macOS CodeResources", &code_resources) {
        Ok(metadata) => metadata,
        Err(error) if error.to_string().contains("does not exist") => {
            return Err(
                "macOS signed bundle evidence is missing Contents/_CodeSignature/CodeResources"
                    .into(),
            );
        }
        Err(error) => return Err(error),
    };
    if metadata.len() > MACOS_CODE_RESOURCES_MAX_BYTES {
        return Err(format!(
            "macOS CodeResources is too large: {} bytes exceeds maximum {MACOS_CODE_RESOURCES_MAX_BYTES}",
            metadata.len()
        )
        .into());
    }

    let plist = plist::Value::from_file(&code_resources)
        .map_err(|error| format!("CodeResources is not a parseable plist: {error}"))?;
    let dict = plist
        .as_dictionary()
        .ok_or("CodeResources plist root must be a dictionary")?;
    if !has_code_resources_file_map(dict, "files") && !has_code_resources_file_map(dict, "files2") {
        return Err("CodeResources plist must contain files or files2 dictionary entries".into());
    }
    Ok(())
}

fn has_code_resources_file_map(dict: &plist::Dictionary, key: &str) -> bool {
    dict.get(key)
        .and_then(plist::Value::as_dictionary)
        .is_some()
}

fn validate_notarization_evidence(path: &Utf8Path) -> Result<(), Box<dyn std::error::Error>> {
    notarization_evidence(path).map(|_| ())
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
struct NotarizationEvidence {
    accepted: bool,
    stapled: bool,
}

impl NotarizationEvidence {
    const fn is_positive(self) -> bool {
        self.accepted || self.stapled
    }
}

fn notarization_evidence(
    path: &Utf8Path,
) -> Result<NotarizationEvidence, Box<dyn std::error::Error>> {
    let text = read_text_file_no_symlink("notarization evidence", path)?;
    notarization_evidence_from_text(&text)
}

fn notarization_evidence_from_text(
    text: &str,
) -> Result<NotarizationEvidence, Box<dyn std::error::Error>> {
    validate_release_evidence_log_text("notarization evidence log", text)?;

    let lower = text.to_ascii_lowercase();
    if let Some(reason) = notarization_negative_evidence(&lower) {
        return Err(format!("negative notarization evidence found: {reason}").into());
    }

    let accepted = explicit_truthy_marker(&lower, &["notarytool"])
        || explicit_status_marker(&lower, "accepted")
        || notarytool_json_status_accepted(text);
    let stapled = explicit_truthy_marker(&lower, &["stapled"]) || explicit_stapler_success(&lower);
    let evidence = NotarizationEvidence { accepted, stapled };
    if evidence.is_positive() {
        Ok(evidence)
    } else {
        Err("no accepted notarization marker found".into())
    }
}

fn notarization_negative_evidence(text: &str) -> Option<String> {
    for line in text.lines() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        if notarization_metadata_line(line) {
            continue;
        }
        if explicit_falsy_marker_line(line, &["notarization", "notary", "notarytool", "stapled"])
            || explicit_marker_line_matches(line, &["status"], &["rejected", "invalid", "failed"])
        {
            return Some(line.to_string());
        }
        if line_contains_any(
            line,
            &[
                "status: rejected",
                "status=rejected",
                r#""status":"rejected""#,
                r#""status": "rejected""#,
                "status: invalid",
                "status=invalid",
                r#""status":"invalid""#,
                r#""status": "invalid""#,
                "notarytool error",
                "notarization failed",
                "submission failed",
                "stapler failed",
                "staple failed",
                "validate action failed",
            ],
        ) {
            return Some(line.to_string());
        }
    }
    None
}

fn explicit_status_marker(text: &str, value: &str) -> bool {
    text.lines()
        .any(|line| explicit_marker_line_matches(line, &["status"], &[value]))
}

fn notarytool_json_status_accepted(text: &str) -> bool {
    json_status_accepted(text)
        || bracketed_log_section(text, "notarytool").is_some_and(|section| {
            json_status_accepted(&section)
                || bracketed_log_section(&section, "stdout")
                    .is_some_and(|stdout| json_status_accepted(&stdout))
        })
}

fn json_status_accepted(text: &str) -> bool {
    serde_json::from_str::<serde_json::Value>(text.trim())
        .ok()
        .and_then(|value| {
            value
                .as_object()
                .and_then(|object| object.get("status"))
                .and_then(serde_json::Value::as_str)
                .map(str::to_ascii_lowercase)
        })
        .is_some_and(|status| status == "accepted")
}

fn bracketed_log_section(text: &str, section: &str) -> Option<String> {
    let header = format!("[{}]", section.to_ascii_lowercase());
    let mut found = false;
    let mut content = String::new();
    for line in text.lines() {
        let trimmed = line.trim();
        let is_header = trimmed.starts_with('[') && trimmed.ends_with(']');
        if is_header {
            if found {
                break;
            }
            if trimmed.to_ascii_lowercase() == header {
                found = true;
            }
            continue;
        }
        if found && notarization_metadata_line(trimmed) {
            break;
        }
        if found {
            content.push_str(line);
            content.push('\n');
        }
    }
    found.then_some(content)
}

fn explicit_stapler_success(text: &str) -> bool {
    text.lines()
        .any(|line| line.trim() == "the staple and validate action worked!")
}

fn notarization_metadata_line(line: &str) -> bool {
    split_marker_assignment(line).is_some_and(|(key, _)| {
        matches!(
            key.trim().replace('-', "_").as_str(),
            "notary_log" | "stapler_log"
        )
    })
}

fn validate_release_evidence_log_text(
    label: &str,
    value: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    if value.trim().is_empty() {
        return Err(format!("{label} must not be empty").into());
    }
    if value.len() > SIGNING_NOTARIZATION_LOG_MAX_BYTES {
        return Err(
            format!("{label} must be at most {SIGNING_NOTARIZATION_LOG_MAX_BYTES} bytes").into(),
        );
    }
    if value
        .chars()
        .any(|ch| ch.is_control() && !matches!(ch, '\n' | '\r' | '\t'))
    {
        return Err(
            format!("{label} must not contain control characters other than tab/newline").into(),
        );
    }
    if value.chars().any(is_release_action_unsafe_format_char) {
        return Err(format!("{label} must not contain unsafe Unicode format characters").into());
    }
    Ok(())
}

fn print_release_check_report(
    report: &ReleaseCheckReport,
    format: &str,
    report_path: Option<&Utf8Path>,
) -> Result<(), Box<dyn std::error::Error>> {
    write_release_check_report(report_path, report)?;
    match format {
        "json" => println!("{}", serde_json::to_string_pretty(report)?),
        "markdown" | "md" => {
            println!("# Vesty Release Check\n");
            println!("status: {}", report.status);
            println!();
            println!("| Check | Status | Value | Hint |");
            println!("| --- | --- | --- | --- |");
            for check in &report.checks {
                println!(
                    "| {} | {} | {} | {} |",
                    check.name,
                    check.status,
                    check.value,
                    check.hint.as_deref().unwrap_or("")
                );
            }
            println!();
            print_daw_matrix(&report.daw_matrix, "markdown")?;
        }
        _ => return Err(format!("unsupported release check format '{format}'").into()),
    }
    Ok(())
}

fn write_release_check_report(
    path: Option<&Utf8Path>,
    report: &ReleaseCheckReport,
) -> Result<(), Box<dyn std::error::Error>> {
    if let Err(error) = validate_release_check_report_shape(report) {
        return Err(std::io::Error::new(
            std::io::ErrorKind::InvalidData,
            format!("invalid release-check report: {error}"),
        )
        .into());
    }
    let Some(path) = path else {
        return Ok(());
    };
    let text = serde_json::to_string_pretty(report)?;
    write_text_file(path, &(text + "\n"))
}

#[cfg(test)]
fn collect_reaper_evidence(dir: &Utf8PathBuf) -> serde_json::Value {
    let profile = vesty_core::find_host_profile("reaper").expect("REAPER profile exists");
    collect_reaper_evidence_for_profile(profile, dir)
}

fn collect_reaper_evidence_for_profile(
    profile: &vesty_core::HostProfile,
    dir: &Utf8PathBuf,
) -> serde_json::Value {
    if daw_evidence_dir_status(dir) == DawEvidenceDirStatus::Blocked {
        return missing_daw_row(profile.name, dir);
    }

    let scan_marker = read_first_optional(dir, &["scan-smoke.log", "scan.log"]);
    let load = read_optional(dir.join("load-smoke.log"));
    let restore = read_optional(dir.join("restore-smoke.log"));
    let ui = read_optional(dir.join("ui-smoke.log"));
    let render = read_optional(dir.join("render-smoke.log"));
    let param_watch = read_optional(dir.join("param-watch.log"));
    let bridge_trace = read_optional(dir.join("bridge-trace.log"));
    let meter_stream = read_optional(dir.join("meter-stream.log"));
    let automation = read_optional(dir.join("automation-smoke.log"));
    let buffer_sample_rate = read_first_optional(
        dir,
        &["buffer-sample-rate.log", "buffer-sample-rate-smoke.log"],
    );
    let offline_render = read_optional(dir.join("offline-render.log"));
    let (platform, platform_supported) =
        evidence_platform_for_profile(profile, dir, Some("macOS arm64"));
    let scan = scan_marker
        .as_deref()
        .map(|text| daw_marker_matches_for_profile(profile, text, generic_scan_ok))
        .unwrap_or_else(|| {
            reaper_scan_cache()
                .and_then(read_optional)
                .is_some_and(|text| {
                    daw_marker_matches_for_profile(profile, &text, |text| {
                        [
                            "VestyGain.vst3",
                            "VestyWebUIDemo.vst3",
                            "VestyMIDISynth.vst3",
                        ]
                        .iter()
                        .all(|needle| text.contains(needle))
                    })
                })
        });

    let load_ok = load.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, |text| {
            ["Vesty Gain", "Vesty Web UI Demo", "Vesty MIDI Synth"]
                .iter()
                .all(|needle| text.contains(needle))
                && text.matches("ok=true").count() >= 3
                || generic_load_ok(text)
        })
    });
    let restore_ok = restore.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, |text| {
            (text.contains("track_count=3") && text.matches("ok=true").count() >= 3)
                || generic_restore_ok(text)
        })
    });
    let ui_ok = ui.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, |text| {
            (text.contains("target_fx=VST3: Vesty Web UI Demo (Vesty)|ok=true")
                && text.contains("ui_show_called=true"))
                || generic_ui_ok(text)
        })
    });
    let automation_ok = render
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_automation_ok))
        || automation.as_deref().is_some_and(|text| {
            daw_marker_matches_for_profile(profile, text, generic_automation_ok)
        });
    let ui_host_param_ok = param_watch
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_ui_host_ok))
        || read_optional(dir.join("ui-host-smoke.log"))
            .as_deref()
            .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_ui_host_ok))
        || bridge_trace.as_deref().is_some_and(|text| {
            daw_marker_matches_for_profile(profile, text, bridge_trace_relayed_param_gesture)
        });
    let meter_stream_ok = meter_stream
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, meter_stream_delivered))
        || bridge_trace.as_deref().is_some_and(|text| {
            daw_marker_matches_for_profile(profile, text, meter_stream_delivered)
        });
    let buffer_sample_rate_ok = buffer_sample_rate.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, generic_buffer_sample_rate_change_ok)
    });
    let offline_render_ok = render.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, |text| {
            generic_offline_render_ok(text) || render_file_evidence_ok(text, dir)
        })
    }) || offline_render.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, |text| {
            generic_offline_render_ok(text) || render_file_evidence_ok(text, dir)
        })
    });

    serde_json::json!({
        "host": profile.name,
        "platform": platform,
        "platform_supported": platform_supported,
        "scan": scan,
        "load": load_ok,
        "ui": ui_ok,
        "ui_host_param": ui_host_param_ok,
        "meter_stream": meter_stream_ok,
        "automation": automation_ok,
        "buffer_sample_rate_change": buffer_sample_rate_ok,
        "save_restore": restore_ok,
        "offline_render": offline_render_ok,
        "evidence": dir.to_string(),
    })
}

#[cfg(test)]
fn collect_generic_daw_evidence(host: &str, dir: &Utf8PathBuf) -> serde_json::Value {
    let Some(profile) = vesty_core::find_host_profile(host) else {
        return missing_daw_row(host, dir);
    };
    collect_generic_daw_evidence_for_profile(profile, dir)
}

fn collect_generic_daw_evidence_for_profile(
    profile: &vesty_core::HostProfile,
    dir: &Utf8PathBuf,
) -> serde_json::Value {
    if daw_evidence_dir_status(dir) != DawEvidenceDirStatus::Present {
        return missing_daw_row(profile.name, dir);
    }

    let (platform, platform_supported) = evidence_platform_for_profile(profile, dir, None);
    let scan = read_first_optional(dir, &["scan-smoke.log", "scan.log"]);
    let load = read_first_optional(dir, &["load-smoke.log", "load.log"]);
    let ui = read_first_optional(dir, &["ui-smoke.log", "ui.log"]);
    let ui_host = read_first_optional(dir, &["ui-host-smoke.log", "param-watch.log"]);
    let meter = read_first_optional(dir, &["meter-stream.log"]);
    let bridge_trace = read_optional(dir.join("bridge-trace.log"));
    let automation = read_first_optional(dir, &["automation-smoke.log", "render-smoke.log"]);
    let buffer_sample_rate = read_first_optional(
        dir,
        &["buffer-sample-rate.log", "buffer-sample-rate-smoke.log"],
    );
    let restore = read_first_optional(dir, &["restore-smoke.log", "restore.log"]);
    let render = read_first_optional(dir, &["render-smoke.log", "offline-render.log"]);

    let scan_ok = scan
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_scan_ok));
    let load_ok = load
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_load_ok));
    let ui_ok = ui
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_ui_ok));
    let ui_host_param_ok = ui_host
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_ui_host_ok))
        || bridge_trace.as_deref().is_some_and(|text| {
            daw_marker_matches_for_profile(profile, text, bridge_trace_relayed_param_gesture)
        });
    let meter_stream_ok = meter
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, meter_stream_delivered))
        || bridge_trace.as_deref().is_some_and(|text| {
            daw_marker_matches_for_profile(profile, text, meter_stream_delivered)
        });
    let automation_ok = automation
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_automation_ok));
    let buffer_sample_rate_ok = buffer_sample_rate.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, generic_buffer_sample_rate_change_ok)
    });
    let save_restore_ok = restore
        .as_deref()
        .is_some_and(|text| daw_marker_matches_for_profile(profile, text, generic_restore_ok));
    let offline_render_ok = render.as_deref().is_some_and(|text| {
        daw_marker_matches_for_profile(profile, text, |text| {
            generic_offline_render_ok(text) || render_file_evidence_ok(text, dir)
        })
    });

    serde_json::json!({
        "host": profile.name,
        "platform": platform,
        "platform_supported": platform_supported,
        "scan": scan_ok,
        "load": load_ok,
        "ui": ui_ok,
        "ui_host_param": ui_host_param_ok,
        "meter_stream": meter_stream_ok,
        "automation": automation_ok,
        "buffer_sample_rate_change": buffer_sample_rate_ok,
        "save_restore": save_restore_ok,
        "offline_render": offline_render_ok,
        "evidence": dir.to_string(),
    })
}

fn missing_daw_row(host: &str, dir: &Utf8PathBuf) -> serde_json::Value {
    serde_json::json!({
        "host": host,
        "platform": "manual matrix pending",
        "platform_supported": false,
        "scan": false,
        "load": false,
        "ui": false,
        "ui_host_param": false,
        "meter_stream": false,
        "automation": false,
        "buffer_sample_rate_change": false,
        "save_restore": false,
        "offline_render": false,
        "evidence": dir.to_string(),
    })
}

fn read_optional(path: Utf8PathBuf) -> Option<String> {
    read_text_file_no_symlink("DAW evidence marker", &path).ok()
}

fn read_first_optional(dir: &Utf8PathBuf, names: &[&str]) -> Option<String> {
    names.iter().find_map(|name| read_optional(dir.join(name)))
}

fn evidence_platform_for_profile(
    profile: &vesty_core::HostProfile,
    dir: &Utf8PathBuf,
    default_platform: Option<&str>,
) -> (String, bool) {
    let platform_path = dir.join("platform.txt");
    let platform_text = read_optional(platform_path.clone());
    let platform_path_exists = fs::symlink_metadata(&platform_path).is_ok();
    let (display, validation_text) = match platform_text {
        Some(text) => {
            let display = text
                .lines()
                .map(str::trim)
                .find(|line| !line.is_empty())
                .map(str::to_string)
                .unwrap_or_else(|| "manual evidence".to_string());
            (display, Some(text.trim().to_string()))
        }
        None if platform_path_exists => ("manual evidence".to_string(), None),
        None => {
            let display = default_platform.unwrap_or("manual evidence").to_string();
            (display.clone(), default_platform.map(str::to_string))
        }
    };
    let supported = validation_text
        .as_deref()
        .is_some_and(|text| daw_platform_evidence_supported(profile, text));
    (display, supported)
}

fn daw_platform_evidence_supported(profile: &vesty_core::HostProfile, value: &str) -> bool {
    required_daw_platform_marker(profile, Some(value.to_string())).is_ok()
}

fn reaper_scan_cache() -> Option<Utf8PathBuf> {
    let home = std::env::var("HOME").ok()?;
    Some(
        Utf8PathBuf::from(home)
            .join("Library/Application Support/REAPER/reaper-vstplugins_arm64.ini"),
    )
}

fn render_file_from_log(text: &str) -> Option<Utf8PathBuf> {
    text.lines().find_map(|line| {
        let (key, value) = line.trim().split_once('=')?;
        if !key.trim().eq_ignore_ascii_case("render_file") {
            return None;
        }
        let value = value.trim().trim_matches('"').trim_matches('\'').trim();
        (!value.is_empty()).then(|| Utf8PathBuf::from(value))
    })
}

fn render_file_evidence_ok(text: &str, evidence_dir: &Utf8Path) -> bool {
    render_file_from_log(text).is_some_and(|path| {
        let path = if path.is_absolute() {
            path
        } else if path.as_str().split(['/', '\\']).any(|part| part == "..") {
            return false;
        } else {
            evidence_dir.join(path)
        };
        render_file_exists_and_nonempty(path)
    })
}

fn render_file_exists_and_nonempty(path: Utf8PathBuf) -> bool {
    require_existing_file_no_symlink("render file evidence", &path)
        .map(|metadata| metadata.len() > 0)
        .unwrap_or(false)
}

fn reaper_param_watch_moved(text: &str) -> bool {
    if !text.contains("target_fx=VST3: Vesty Web UI Demo (Vesty)|ok=true") {
        return false;
    }

    let values = text
        .lines()
        .filter_map(|line| line.split_once("param0="))
        .filter_map(|(_, value)| value.parse::<f64>().ok());
    let mut saw_initial = false;
    let mut saw_target = false;
    for value in values {
        saw_initial |= (0.49..=0.51).contains(&value);
        saw_target |= value >= 0.88;
    }
    saw_initial && saw_target
}

fn daw_marker_matches(text: &str, predicate: impl FnOnce(&str) -> bool) -> bool {
    daw_marker_positive(text) && predicate(text)
}

fn daw_marker_matches_for_profile(
    profile: &vesty_core::HostProfile,
    text: &str,
    predicate: impl FnOnce(&str) -> bool,
) -> bool {
    daw_marker_positive(text) && daw_marker_host_scope_matches(profile, text) && predicate(text)
}

fn daw_marker_positive(text: &str) -> bool {
    !daw_marker_has_missing_assignment(text) && !daw_marker_has_negative_evidence(text)
}

fn daw_marker_host_scope_matches(profile: &vesty_core::HostProfile, text: &str) -> bool {
    for (key, value) in text.lines().flat_map(marker_assignments) {
        let key = key.trim().to_ascii_lowercase().replace('-', "_");
        if !matches!(
            key.as_str(),
            "host" | "daw" | "daw_host" | "host_profile" | "profile"
        ) {
            continue;
        }
        let value = value
            .trim()
            .trim_matches(['`', '"', '\''])
            .trim_end_matches([',', ';']);
        let Some(found) = vesty_core::find_host_profile(value) else {
            return false;
        };
        if found.id != profile.id {
            return false;
        }
    }
    true
}

fn bridge_trace_relayed_param_gesture(text: &str) -> bool {
    let legacy_trace = text.contains("ParamGesture { phase: Begin")
        && text.contains("ParamGesture { phase: Perform")
        && text.contains("ParamGesture { phase: End");
    let packet_trace = text.contains(r#""type":"param.begin""#)
        && text.contains(r#""type":"param.perform""#)
        && text.contains(r#""type":"param.end""#);
    (legacy_trace || packet_trace) && text.contains("result=0")
}

fn generic_scan_ok(text: &str) -> bool {
    explicit_truthy_marker(text, &["scan", "scan_ok"])
        || [
            "VestyGain.vst3",
            "VestyWebUIDemo.vst3",
            "VestyMIDISynth.vst3",
        ]
        .iter()
        .all(|needle| text.contains(needle))
}

fn generic_load_ok(text: &str) -> bool {
    explicit_truthy_marker(text, &["load", "load_ok"])
        || (vesty_plugin_names_present(text) && text.matches("ok=true").count() >= 3)
}

fn generic_ui_ok(text: &str) -> bool {
    explicit_truthy_marker(text, &["ui", "ui_ok"])
        || (text.contains("Vesty Web UI Demo") && text.contains("ui_show_called=true"))
}

fn generic_ui_host_ok(text: &str) -> bool {
    explicit_truthy_marker(text, &["ui_host_param", "ui_host", "host_param"])
        || reaper_param_watch_moved(text)
}

fn generic_automation_ok(text: &str) -> bool {
    explicit_truthy_marker(text, &["automation", "automation_ok"])
        || (text.contains("automation_points=3")
            && text.contains("midi_note_inserted=true")
            && text.contains("project_ready=true"))
}

fn generic_buffer_sample_rate_change_ok(text: &str) -> bool {
    explicit_truthy_marker(
        text,
        &[
            "buffer_sample_rate_change",
            "buffer_change",
            "buffer_size_change",
            "sample_rate_change",
        ],
    ) || (text.contains("buffer_size_changed=true") && text.contains("sample_rate_changed=true"))
}

fn generic_restore_ok(text: &str) -> bool {
    explicit_truthy_marker(text, &["save_restore", "restore", "restore_ok"])
        || (text.contains("track_count=3") && text.matches("ok=true").count() >= 3)
}

fn generic_offline_render_ok(text: &str) -> bool {
    explicit_truthy_marker(text, &["offline_render", "render", "render_ok"])
}

fn vesty_plugin_names_present(text: &str) -> bool {
    ["Vesty Gain", "Vesty Web UI Demo", "Vesty MIDI Synth"]
        .iter()
        .all(|needle| text.contains(needle))
}

fn explicit_truthy_marker(text: &str, keys: &[&str]) -> bool {
    text.lines()
        .any(|line| explicit_truthy_marker_line(line, keys))
}

fn explicit_truthy_marker_line(line: &str, keys: &[&str]) -> bool {
    explicit_marker_line_matches(line, keys, &["true", "pass", "ok"])
}

fn explicit_falsy_marker_line(line: &str, keys: &[&str]) -> bool {
    explicit_marker_line_matches(
        line,
        keys,
        &[
            "false", "fail", "failed", "error", "invalid", "rejected", "pending",
        ],
    )
}

fn explicit_marker_line_matches(line: &str, keys: &[&str], values: &[&str]) -> bool {
    line.split(';')
        .any(|fragment| explicit_marker_fragment_matches(fragment, keys, values))
}

fn explicit_marker_fragment_matches(fragment: &str, keys: &[&str], values: &[&str]) -> bool {
    let normalized = fragment.trim().to_ascii_lowercase().replace('-', "_");
    let Some((raw_key, raw_value)) = split_marker_assignment(&normalized) else {
        return false;
    };

    let key = raw_key.trim().trim_matches(['`', '"', '\'']);
    let value = raw_value
        .trim()
        .trim_start_matches(['`', '"', '\''])
        .split(|ch: char| !(ch.is_ascii_alphanumeric() || ch == '_'))
        .find(|token| !token.is_empty())
        .unwrap_or_default();
    if !values.contains(&value) {
        return false;
    }

    keys.iter().any(|candidate| {
        let candidate = candidate.to_ascii_lowercase().replace('-', "_");
        key == candidate || key == format!("{candidate}_ok")
    })
}

fn line_contains_any(line: &str, needles: &[&str]) -> bool {
    needles.iter().any(|needle| line.contains(needle))
}

fn split_marker_assignment(line: &str) -> Option<(&str, &str)> {
    if let Some((key, value)) = line.split_once('=') {
        Some((key, value))
    } else {
        line.split_once(':')
    }
}

fn marker_assignments(line: &str) -> impl Iterator<Item = (&str, &str)> {
    line.split(';').filter_map(split_marker_assignment)
}

fn meter_stream_delivered(text: &str) -> bool {
    let flush_sent = text.lines().any(|line| {
        line.contains("meter_flush sent=")
            && !line.contains("meter_flush sent=0")
            && !line.contains("meter_flush sent=false")
    });
    let bridge_packet = text.contains(r#""lane":"meter""#)
        && text.contains(r#""type":"meter.main""#)
        && (text.contains(r#""peaks""#) || text.contains(r#""rms""#));
    let log_frame = text.contains("meter.main")
        && (text.contains("peaks=")
            || text.contains("rms=")
            || text.lines().any(line_has_nonzero_peak));
    flush_sent || bridge_packet || log_frame
}

fn line_has_nonzero_peak(line: &str) -> bool {
    line.split_once("peak=")
        .and_then(|(_, rest)| {
            rest.split(|char: char| !(char.is_ascii_digit() || matches!(char, '.' | '-' | '+')))
                .next()
        })
        .and_then(|value| value.parse::<f64>().ok())
        .is_some_and(|value| value > 0.0)
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum DevInstallMode {
    Copy,
    Symlink,
}

fn parse_dev_install_mode(mode: &str) -> Result<DevInstallMode, Box<dyn std::error::Error>> {
    match mode.trim().to_ascii_lowercase().as_str() {
        "copy" => Ok(DevInstallMode::Copy),
        "symlink" | "link" => Ok(DevInstallMode::Symlink),
        _ => Err(format!("unsupported install mode '{mode}'; expected copy or symlink").into()),
    }
}

fn default_user_vst3_dir() -> Option<Utf8PathBuf> {
    if cfg!(target_os = "macos") {
        std::env::var("HOME")
            .ok()
            .map(Utf8PathBuf::from)
            .map(|home| home.join("Library/Audio/Plug-Ins/VST3"))
    } else if cfg!(target_os = "windows") {
        std::env::var("CommonProgramFiles")
            .ok()
            .map(Utf8PathBuf::from)
            .map(|root| root.join("VST3"))
    } else if cfg!(target_os = "linux") {
        std::env::var("HOME")
            .ok()
            .map(Utf8PathBuf::from)
            .map(|home| home.join(".vst3"))
    } else {
        None
    }
}

fn install_dev_bundle_from_options(
    bundle_dir: &Utf8Path,
    vst3_dir: Option<Utf8PathBuf>,
    install_mode: &str,
) -> Result<Utf8PathBuf, Box<dyn std::error::Error>> {
    let mode = parse_dev_install_mode(install_mode)?;
    let target_dir = match vst3_dir {
        Some(dir) => dir,
        None => default_user_vst3_dir()
            .ok_or("could not determine default user VST3 directory; pass --vst3-dir")?,
    };
    install_dev_bundle(bundle_dir, &target_dir, mode)
}

fn install_dev_bundle(
    bundle_dir: &Utf8Path,
    vst3_dir: &Utf8Path,
    mode: DevInstallMode,
) -> Result<Utf8PathBuf, Box<dyn std::error::Error>> {
    if bundle_dir.extension() != Some("vst3") {
        return Err(format!("dev install source must be a .vst3 directory: {bundle_dir}").into());
    }
    require_existing_directory_no_symlink("dev install source", bundle_dir)?;
    let name = bundle_dir
        .file_name()
        .ok_or("dev install source has no bundle file name")?;
    create_directory_no_parent_or_leaf_symlink("dev install directory", vst3_dir)?;
    let destination = vst3_dir.join(name);
    remove_existing_dev_bundle(&destination)?;
    match mode {
        DevInstallMode::Copy => copy_bundle_dir(bundle_dir, &destination)?,
        DevInstallMode::Symlink => symlink_bundle_dir(bundle_dir, &destination)?,
    }
    Ok(destination)
}

fn remove_existing_dev_bundle(path: &Utf8Path) -> Result<(), Box<dyn std::error::Error>> {
    let metadata = match fs::symlink_metadata(path) {
        Ok(metadata) => metadata,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(()),
        Err(error) => return Err(error.into()),
    };
    if metadata.file_type().is_symlink() || metadata.is_file() {
        fs::remove_file(path)?;
    } else if metadata.is_dir() {
        fs::remove_dir_all(path)?;
    }
    Ok(())
}

fn copy_bundle_dir(
    source: &Utf8Path,
    destination: &Utf8Path,
) -> Result<(), Box<dyn std::error::Error>> {
    create_directory_no_parent_or_leaf_symlink("dev install bundle directory", destination)?;
    for entry in fs::read_dir(source)? {
        let entry = entry?;
        let source_path = Utf8PathBuf::from_path_buf(entry.path())
            .map_err(|_| "bundle path is not valid utf-8")?;
        let metadata = fs::symlink_metadata(&source_path)?;
        if metadata.file_type().is_symlink() {
            return Err(format!("dev install refuses symlink in bundle: {source_path}").into());
        }
        let destination_path = destination.join(
            source_path
                .file_name()
                .ok_or("bundle entry has no file name")?,
        );
        if metadata.is_dir() {
            copy_bundle_dir(&source_path, &destination_path)?;
        } else if metadata.is_file() {
            reject_existing_path_symlink("dev install bundle file", &destination_path)?;
            reject_existing_output_parent_symlink("dev install bundle file", &destination_path)?;
            fs::copy(&source_path, &destination_path)?;
        }
    }
    Ok(())
}

#[cfg(unix)]
fn symlink_bundle_dir(
    source: &Utf8Path,
    destination: &Utf8Path,
) -> Result<(), Box<dyn std::error::Error>> {
    std::os::unix::fs::symlink(source, destination)?;
    Ok(())
}

#[cfg(windows)]
fn symlink_bundle_dir(
    source: &Utf8Path,
    destination: &Utf8Path,
) -> Result<(), Box<dyn std::error::Error>> {
    std::os::windows::fs::symlink_dir(source, destination)?;
    Ok(())
}

#[cfg(not(any(unix, windows)))]
fn symlink_bundle_dir(
    _source: &Utf8Path,
    _destination: &Utf8Path,
) -> Result<(), Box<dyn std::error::Error>> {
    Err("symlink install mode is unsupported on this platform".into())
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct CommandSpec {
    program: String,
    args: Vec<String>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
enum NotarizationCredentials {
    KeychainProfile(String),
    AppleId {
        apple_id: String,
        team_id: String,
        password: String,
    },
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct NotarizationPlan {
    archive: Utf8PathBuf,
    commands: Vec<CommandSpec>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct NotarizeOptions {
    bundle: Utf8PathBuf,
    keychain_profile: Option<String>,
    apple_id: Option<String>,
    team_id: Option<String>,
    password: Option<String>,
    archive: Option<Utf8PathBuf>,
    wait: bool,
    staple: bool,
}

fn bundle_signing_command(
    platform: BundlePlatform,
    bundle_dir: &Utf8Path,
    binary_path: &Utf8Path,
    identity: &str,
) -> Result<CommandSpec, Box<dyn std::error::Error>> {
    let identity = identity.trim();
    if identity.is_empty() {
        return Err("package signing identity cannot be empty".into());
    }

    match platform {
        BundlePlatform::Macos => {
            let program = find_command("codesign", &[Utf8PathBuf::from("/usr/bin/codesign")])
                .map(|path| path.to_string())
                .unwrap_or_else(|| "codesign".to_string());
            Ok(CommandSpec {
                program,
                args: vec![
                    "--force".to_string(),
                    "--deep".to_string(),
                    "--options".to_string(),
                    "runtime".to_string(),
                    "--timestamp".to_string(),
                    "--sign".to_string(),
                    identity.to_string(),
                    portable_report_path(bundle_dir),
                ],
            })
        }
        BundlePlatform::WindowsX64 => {
            let program = find_command("signtool.exe", &windows_signtool_candidates())
                .map(|path| path.to_string())
                .unwrap_or_else(|| "signtool.exe".to_string());
            Ok(CommandSpec {
                program,
                args: vec![
                    "sign".to_string(),
                    "/fd".to_string(),
                    "SHA256".to_string(),
                    "/td".to_string(),
                    "SHA256".to_string(),
                    "/tr".to_string(),
                    "http://timestamp.digicert.com".to_string(),
                    "/n".to_string(),
                    identity.to_string(),
                    portable_report_path(binary_path),
                ],
            })
        }
        BundlePlatform::LinuxX64 => Err(
            "Linux VST3 bundle signing is release-channel specific; sign distro packages or installers outside `vesty package`"
                .into(),
        ),
    }
}

fn signing_verification_command(
    platform: BundlePlatform,
    bundle_dir: &Utf8Path,
    binary_path: Option<&Utf8Path>,
    tool: Option<&Utf8Path>,
) -> Result<CommandSpec, Box<dyn std::error::Error>> {
    if bundle_dir.extension() != Some("vst3") {
        return Err(
            format!("signing verification target must be a .vst3 bundle: {bundle_dir}").into(),
        );
    }
    require_existing_directory_no_symlink("signing verification target", bundle_dir)?;

    match platform {
        BundlePlatform::Macos => {
            if let Some(binary_path) = binary_path {
                return Err(format!(
                    "macOS signing verification checks the .vst3 bundle; --binary is only supported for windows-x64: {binary_path}"
                )
                .into());
            }
            let program = signing_verification_program(
                tool,
                "codesign",
                &[Utf8PathBuf::from("/usr/bin/codesign")],
            )?;
            Ok(CommandSpec {
                program,
                args: vec![
                    "--verify".to_string(),
                    "--deep".to_string(),
                    "--strict".to_string(),
                    "--verbose=2".to_string(),
                    portable_report_path(bundle_dir),
                ],
            })
        }
        BundlePlatform::WindowsX64 => {
            let binary_path = match binary_path {
                Some(path) => path.to_path_buf(),
                None => infer_windows_bundle_binary(bundle_dir)?,
            };
            require_windows_signing_binary_in_bundle(bundle_dir, &binary_path)?;
            let program =
                signing_verification_program(tool, "signtool.exe", &windows_signtool_candidates())?;
            Ok(CommandSpec {
                program,
                args: vec![
                    "verify".to_string(),
                    "/pa".to_string(),
                    "/v".to_string(),
                    portable_report_path(&binary_path),
                ],
            })
        }
        BundlePlatform::LinuxX64 => Err(
            "Linux VST3 signing evidence is release-channel specific; collect distro/package signing evidence outside `vesty release-evidence collect-signing`"
                .into(),
        ),
    }
}

fn signing_verification_program(
    tool: Option<&Utf8Path>,
    default_binary: &str,
    candidates: &[Utf8PathBuf],
) -> Result<String, Box<dyn std::error::Error>> {
    if let Some(tool) = tool {
        reject_existing_output_parent_symlink("signing verification tool", tool)?;
        reject_existing_path_symlink("signing verification tool", tool)?;
        return Ok(tool.to_string());
    }
    Ok(find_command(default_binary, candidates)
        .map(|path| path.to_string())
        .unwrap_or_else(|| default_binary.to_string()))
}

fn require_windows_signing_binary_in_bundle(
    bundle_dir: &Utf8Path,
    binary_path: &Utf8Path,
) -> Result<(), Box<dyn std::error::Error>> {
    require_existing_file_no_symlink("Windows signing verification binary", binary_path)?;
    if !binary_path
        .extension()
        .is_some_and(|extension| extension.eq_ignore_ascii_case("vst3"))
    {
        return Err(format!(
            "Windows signing verification binary must be a .vst3 file: {binary_path}"
        )
        .into());
    }

    let platform_dir = bundle_dir.join("Contents/x86_64-win");
    require_existing_directory_no_symlink("Windows signing payload directory", &platform_dir)?;
    let platform_dir = canonicalize_utf8(&platform_dir)?;
    let binary_path = canonicalize_utf8(binary_path)?;
    if !binary_path.starts_with(&platform_dir) {
        return Err(format!(
            "Windows signing verification binary must be inside bundle Contents/x86_64-win: {binary_path}"
        )
        .into());
    }
    Ok(())
}

fn infer_windows_bundle_binary(
    bundle_dir: &Utf8Path,
) -> Result<Utf8PathBuf, Box<dyn std::error::Error>> {
    let platform_dir = bundle_dir.join("Contents/x86_64-win");
    if !existing_directory_no_symlink("Windows signing payload directory", &platform_dir)? {
        return Err(format!(
            "Windows signing verification needs Contents/x86_64-win in bundle or explicit --binary: {bundle_dir}"
        )
        .into());
    }

    let mut candidates = Vec::new();
    for entry in fs::read_dir(&platform_dir)? {
        let entry = entry?;
        let path = Utf8PathBuf::from_path_buf(entry.path())
            .map_err(|_| "Windows signing binary path is not valid utf-8")?;
        let metadata = fs::symlink_metadata(&path)?;
        if metadata.file_type().is_symlink() {
            return Err(format!("Windows signing binary must not be a symlink: {path}").into());
        }
        if metadata.is_file()
            && path
                .extension()
                .is_some_and(|extension| extension.eq_ignore_ascii_case("vst3"))
        {
            candidates.push(path);
        }
    }
    candidates.sort();
    match candidates.as_slice() {
        [path] => Ok(path.clone()),
        [] => Err(format!("no Windows .vst3 platform binary found under {platform_dir}").into()),
        _ => Err(format!(
            "multiple Windows .vst3 platform binaries found under {platform_dir}; pass --binary"
        )
        .into()),
    }
}

fn run_signing_command(command: &CommandSpec) -> Result<(), Box<dyn std::error::Error>> {
    run_command_spec(command, "signing")
}

fn run_command_spec(command: &CommandSpec, label: &str) -> Result<(), Box<dyn std::error::Error>> {
    let status = Command::new(&command.program)
        .args(&command.args)
        .status()?;
    if status.success() {
        Ok(())
    } else {
        Err(format!(
            "{label} command failed: {} {}",
            command.program,
            command.args.join(" ")
        )
        .into())
    }
}

fn run_command_spec_capture(
    command: &CommandSpec,
    label: &str,
) -> Result<Output, Box<dyn std::error::Error>> {
    let output = Command::new(&command.program)
        .args(&command.args)
        .output()?;
    if output.status.success() {
        Ok(output)
    } else {
        let stdout = String::from_utf8_lossy(&output.stdout);
        let stderr = String::from_utf8_lossy(&output.stderr);
        Err(format!(
            "{label} command failed: {} {}\nstdout:\n{}\nstderr:\n{}",
            command.program,
            command.args.join(" "),
            stdout.trim_end(),
            stderr.trim_end()
        )
        .into())
    }
}

fn captured_command_log(command: &CommandSpec, output: &Output) -> String {
    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);
    let mut text = format!(
        "command={} {}\nstatus={}\n",
        command.program,
        command.args.join(" "),
        output.status
    );
    if !stdout.is_empty() {
        text.push_str("\n[stdout]\n");
        text.push_str(&stdout);
        if !stdout.ends_with('\n') {
            text.push('\n');
        }
    }
    if !stderr.is_empty() {
        text.push_str("\n[stderr]\n");
        text.push_str(&stderr);
        if !stderr.ends_with('\n') {
            text.push('\n');
        }
    }
    text
}

fn run_notarize(options: NotarizeOptions) -> Result<(), Box<dyn std::error::Error>> {
    if !cfg!(target_os = "macos") {
        return Err("notarization requires macOS with xcrun notarytool".into());
    }
    if !options.bundle.is_dir() || options.bundle.extension() != Some("vst3") {
        return Err(format!(
            "notarization bundle must be a .vst3 directory: {}",
            options.bundle
        )
        .into());
    }
    let credentials = notarization_credentials(
        options.keychain_profile.as_deref(),
        options.apple_id.as_deref(),
        options.team_id.as_deref(),
        options.password.as_deref(),
    )?;
    let plan = notarization_plan(
        &options.bundle,
        options.archive.as_deref(),
        &credentials,
        options.wait,
        options.staple,
    )?;
    for command in &plan.commands {
        run_command_spec(command, "notarization")?;
    }
    println!("notarization archive: {}", plan.archive);
    if options.staple {
        println!("stapled: {}", options.bundle);
    }
    Ok(())
}

fn notarization_credentials(
    keychain_profile: Option<&str>,
    apple_id: Option<&str>,
    team_id: Option<&str>,
    password: Option<&str>,
) -> Result<NotarizationCredentials, Box<dyn std::error::Error>> {
    let keychain_profile = keychain_profile
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let apple_id = apple_id.map(str::trim).filter(|value| !value.is_empty());
    let team_id = team_id.map(str::trim).filter(|value| !value.is_empty());
    let password = password.map(str::trim).filter(|value| !value.is_empty());

    if let Some(profile) = keychain_profile {
        if apple_id.is_some() || team_id.is_some() || password.is_some() {
            return Err(
                "use either --keychain-profile or --apple-id/--team-id/--password, not both".into(),
            );
        }
        return Ok(NotarizationCredentials::KeychainProfile(
            profile.to_string(),
        ));
    }

    match (apple_id, team_id, password) {
        (Some(apple_id), Some(team_id), Some(password)) => Ok(NotarizationCredentials::AppleId {
            apple_id: apple_id.to_string(),
            team_id: team_id.to_string(),
            password: password.to_string(),
        }),
        _ => {
            Err("provide --keychain-profile or all of --apple-id, --team-id and --password".into())
        }
    }
}

fn notarization_plan(
    bundle: &Utf8Path,
    archive: Option<&Utf8Path>,
    credentials: &NotarizationCredentials,
    wait: bool,
    staple: bool,
) -> Result<NotarizationPlan, Box<dyn std::error::Error>> {
    if !wait && staple {
        return Err("--no-wait cannot be used with stapling; pass --no-staple".into());
    }

    let archive = archive
        .map(Utf8Path::to_path_buf)
        .unwrap_or_else(|| Utf8PathBuf::from(format!("{bundle}.zip")));
    let ditto = find_command("ditto", &[Utf8PathBuf::from("/usr/bin/ditto")])
        .map(|path| path.to_string())
        .unwrap_or_else(|| "ditto".to_string());
    let xcrun = find_command("xcrun", &[Utf8PathBuf::from("/usr/bin/xcrun")])
        .map(|path| path.to_string())
        .unwrap_or_else(|| "xcrun".to_string());

    let mut commands = Vec::new();
    commands.push(CommandSpec {
        program: ditto,
        args: vec![
            "-c".to_string(),
            "-k".to_string(),
            "--keepParent".to_string(),
            bundle.to_string(),
            archive.to_string(),
        ],
    });

    let mut submit_args = vec![
        "notarytool".to_string(),
        "submit".to_string(),
        archive.to_string(),
    ];
    if wait {
        submit_args.push("--wait".to_string());
    }
    match credentials {
        NotarizationCredentials::KeychainProfile(profile) => {
            submit_args.extend(["--keychain-profile".to_string(), profile.clone()]);
        }
        NotarizationCredentials::AppleId {
            apple_id,
            team_id,
            password,
        } => {
            submit_args.extend([
                "--apple-id".to_string(),
                apple_id.clone(),
                "--team-id".to_string(),
                team_id.clone(),
                "--password".to_string(),
                password.clone(),
            ]);
        }
    }
    commands.push(CommandSpec {
        program: xcrun.clone(),
        args: submit_args,
    });

    if staple {
        commands.push(CommandSpec {
            program: xcrun,
            args: vec![
                "stapler".to_string(),
                "staple".to_string(),
                bundle.to_string(),
            ],
        });
    }

    Ok(NotarizationPlan { archive, commands })
}

#[derive(Clone, Debug)]
struct DevOptions {
    config_path: Utf8PathBuf,
    release: bool,
    no_ui: bool,
    ui_command: Option<String>,
    install_dev: bool,
    binary: Option<Utf8PathBuf>,
    platform: Option<String>,
    output_dir: Utf8PathBuf,
    vst3_dir: Option<Utf8PathBuf>,
    install_mode: String,
}

fn run_dev(options: DevOptions) -> Result<(), Box<dyn std::error::Error>> {
    let project_dir = options
        .config_path
        .parent()
        .map(|path| path.to_path_buf())
        .unwrap_or_else(|| Utf8PathBuf::from("."));
    let config = read_config(&options.config_path)?;

    println!("dev: {}", config.plugin.name);
    let mut cargo = Command::new("cargo");
    cargo.current_dir(&project_dir).arg("build");
    if options.release {
        cargo.arg("--release");
    }
    let status = cargo.status()?;
    if !status.success() {
        return Err("cargo build failed".into());
    }

    if options.install_dev {
        let binary =
            resolve_dev_binary_path(options.binary.as_ref(), &project_dir, options.release)?;
        let platform = resolve_bundle_platform(options.platform.as_deref())?;
        let report = package_vst3(
            &config,
            &PackageOptions {
                project_dir: project_dir.clone(),
                output_dir: options.output_dir,
                platform,
                binary_path: binary,
            },
        )?;
        let installed = install_dev_bundle_from_options(
            &report.bundle_dir,
            options.vst3_dir,
            &options.install_mode,
        )?;
        println!("dev bundle: {}", report.bundle_dir);
        println!("installed dev bundle: {installed}");
    }

    let Some(ui) = config.ui else {
        println!("ui: none");
        return Ok(());
    };
    if options.no_ui {
        println!("ui: skipped");
        return Ok(());
    }

    let ui_dir = project_dir.join(&ui.dir);
    if !ui_dir.is_dir() {
        return Err(format!("ui directory does not exist: {ui_dir}").into());
    }
    if let Some(dev_url) = &ui.dev_url {
        println!("ui dev url: {dev_url}");
    }

    let command = options.ui_command.or_else(|| {
        ui_dir
            .join("package.json")
            .is_file()
            .then(|| "npm run dev".to_string())
    });
    let Some(command) = command else {
        println!("ui dev server: no package.json found in {ui_dir}");
        return Ok(());
    };

    println!("ui dev server: {command}");
    run_shell(&command, Some(&ui_dir))
}

fn resolve_dev_binary_path(
    explicit: Option<&Utf8PathBuf>,
    project_dir: &Utf8Path,
    release: bool,
) -> Result<Utf8PathBuf, Box<dyn std::error::Error>> {
    if let Some(binary) = explicit {
        return Ok(binary.clone());
    }

    let metadata = cargo_metadata_json(project_dir)?;
    let manifest_path = canonical_manifest_path(project_dir)?;
    let target_name = cdylib_target_name_from_metadata(&metadata, manifest_path.as_deref())?;
    let target_dir = metadata
        .get("target_directory")
        .and_then(serde_json::Value::as_str)
        .ok_or("cargo metadata did not report target_directory")?;
    let profile = if release { "release" } else { "debug" };
    Ok(Utf8PathBuf::from(target_dir)
        .join(profile)
        .join(cdylib_filename(target_name)))
}

fn cargo_metadata_json(
    project_dir: &Utf8Path,
) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
    let output = Command::new("cargo")
        .current_dir(project_dir)
        .args(["metadata", "--no-deps", "--format-version=1"])
        .output()?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(format!("cargo metadata failed: {}", stderr.trim()).into());
    }
    Ok(serde_json::from_slice(&output.stdout)?)
}

fn canonical_manifest_path(
    project_dir: &Utf8Path,
) -> Result<Option<Utf8PathBuf>, Box<dyn std::error::Error>> {
    let manifest_path = project_dir.join("Cargo.toml");
    if !manifest_path.is_file() {
        return Ok(None);
    }
    let canonical = fs::canonicalize(&manifest_path)?;
    Ok(Some(Utf8PathBuf::from_path_buf(canonical).map_err(
        |_| format!("Cargo manifest path is not UTF-8: {manifest_path}"),
    )?))
}

fn cdylib_target_name_from_metadata<'a>(
    metadata: &'a serde_json::Value,
    manifest_path: Option<&Utf8Path>,
) -> Result<&'a str, Box<dyn std::error::Error>> {
    let packages = metadata
        .get("packages")
        .and_then(serde_json::Value::as_array)
        .ok_or("cargo metadata did not report packages")?;
    let package = cdylib_package_from_metadata(metadata, packages, manifest_path)?;
    let targets = package
        .get("targets")
        .and_then(serde_json::Value::as_array)
        .ok_or("cargo metadata package did not report targets")?;
    targets
        .iter()
        .find(|target| {
            target
                .get("kind")
                .and_then(serde_json::Value::as_array)
                .is_some_and(|kind| kind.iter().any(|value| value.as_str() == Some("cdylib")))
        })
        .and_then(|target| target.get("name").and_then(serde_json::Value::as_str))
        .ok_or_else(|| "cargo metadata root package has no cdylib target".into())
}

fn cdylib_package_from_metadata<'a>(
    metadata: &'a serde_json::Value,
    packages: &'a [serde_json::Value],
    manifest_path: Option<&Utf8Path>,
) -> Result<&'a serde_json::Value, Box<dyn std::error::Error>> {
    if let Some(manifest_path) = manifest_path
        && let Some(package) = packages.iter().find(|package| {
            package
                .get("manifest_path")
                .and_then(serde_json::Value::as_str)
                == Some(manifest_path.as_str())
        })
    {
        return Ok(package);
    }

    if let Some(root_package) = metadata
        .get("root_package")
        .and_then(serde_json::Value::as_str)
        && let Some(package) = packages.iter().find(|package| {
            package.get("id").and_then(serde_json::Value::as_str) == Some(root_package)
        })
    {
        return Ok(package);
    }

    if let Some(member) = metadata
        .get("workspace_default_members")
        .and_then(serde_json::Value::as_array)
        .and_then(|members| (members.len() == 1).then(|| members[0].as_str()).flatten())
        && let Some(package) = packages
            .iter()
            .find(|package| package.get("id").and_then(serde_json::Value::as_str) == Some(member))
    {
        return Ok(package);
    }

    Err("cargo metadata could not identify the plugin package; pass --binary explicitly".into())
}

fn cdylib_filename(target_name: &str) -> String {
    let stem = target_name.replace('-', "_");
    if cfg!(target_os = "windows") {
        format!("{stem}.dll")
    } else if cfg!(target_os = "macos") {
        format!("lib{stem}.dylib")
    } else {
        format!("lib{stem}.so")
    }
}

fn command_version(command: &str) -> String {
    Command::new(command)
        .arg("--version")
        .output()
        .ok()
        .and_then(|output| String::from_utf8(output.stdout).ok())
        .map(|text| text.trim().to_string())
        .unwrap_or_else(|| "not found".to_string())
}

#[derive(Clone, Debug, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
struct DoctorReport {
    #[serde(default, skip_serializing_if = "Option::is_none")]
    os: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    ci_run_url: Option<String>,
    checks: Vec<DoctorCheck>,
}

#[derive(Clone, Debug, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
struct DoctorCheck {
    name: String,
    status: String,
    value: String,
    hint: Option<String>,
}

const DOCTOR_MAX_CHECKS: usize = 128;
const DOCTOR_DAW_HOSTS: [&str; 5] = [
    "REAPER",
    "Cubase/Nuendo",
    "Bitwig Studio",
    "Ableton Live",
    "Studio One",
];

fn known_doctor_check_names() -> BTreeSet<String> {
    let mut names = BTreeSet::new();
    for os in ["Linux", "macOS", "Windows"] {
        names.extend(doctor_allowed_check_names_for_os(os));
    }
    names.insert("signing: release signing".to_string());
    names
}

fn doctor_allowed_check_names_for_os(os: &str) -> BTreeSet<String> {
    required_doctor_check_names(os)
        .into_iter()
        .map(str::to_string)
        .chain(DOCTOR_DAW_HOSTS.map(|host| format!("daw install: {host}")))
        .collect()
}

fn unexpected_doctor_checks_for_os(os: &str, report: &DoctorReport) -> Vec<String> {
    let allowed = doctor_allowed_check_names_for_os(os);
    let mut unexpected = report
        .checks
        .iter()
        .map(|check| check.name.trim())
        .filter(|name| !allowed.contains(*name))
        .map(str::to_string)
        .collect::<Vec<_>>();
    unexpected.sort();
    unexpected.dedup();
    unexpected
}

fn validate_doctor_report(report: &DoctorReport) -> Result<(), Box<dyn std::error::Error>> {
    if let Some(os) = &report.os {
        validate_release_action_text("doctor report os", os)?;
    }
    if let Some(ci_run_url) = &report.ci_run_url {
        validate_release_action_text("doctor report ci run url", ci_run_url)?;
        if !is_github_actions_run_url(ci_run_url) {
            return Err(format!("invalid doctor report ci_run_url `{ci_run_url}`").into());
        }
    }
    if report.checks.is_empty() {
        return Err("doctor report must contain at least one check".into());
    }
    if report.checks.len() > DOCTOR_MAX_CHECKS {
        return Err(format!(
            "doctor report has too many checks: {} exceeds maximum {DOCTOR_MAX_CHECKS}",
            report.checks.len()
        )
        .into());
    }

    let mut seen = BTreeSet::new();
    let known_checks = known_doctor_check_names();
    for check in &report.checks {
        validate_release_action_text("doctor check name", &check.name)?;
        validate_release_action_text(&format!("doctor `{}` status", check.name), &check.status)?;
        validate_release_action_text(&format!("doctor `{}` value", check.name), &check.value)?;
        if let Some(hint) = &check.hint {
            validate_release_action_text(&format!("doctor `{}` hint", check.name), hint)?;
        }
        match check.status.as_str() {
            "ok" | "missing" | "skipped" | "unknown" | "unsupported" => {}
            other => {
                return Err(format!(
                    "doctor check `{}` has unexpected status `{other}`",
                    check.name
                )
                .into());
            }
        }
        let normalized = check.name.trim();
        if !seen.insert(normalized.to_string()) {
            return Err(format!("duplicate doctor check `{normalized}`").into());
        }
        if !known_checks.contains(normalized) {
            return Err(format!("unknown doctor check `{normalized}`").into());
        }
    }
    Ok(())
}

fn run_doctor(format: &str) -> Result<(), Box<dyn std::error::Error>> {
    let format = parse_output_format(format)?;
    let report = doctor_report();
    validate_doctor_report(&report)?;
    match format {
        OutputFormat::Text => {
            for check in &report.checks {
                println!("{}: {}", check.name, check.value);
            }
        }
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&report)?),
    }
    Ok(())
}

fn doctor_report() -> DoctorReport {
    let mut checks = vec![
        command_check("rustc", None),
        command_check("cargo", None),
        command_check(
            "node",
            Some("install Node.js before building Web UI templates"),
        ),
        command_check(
            "npm",
            Some("install npm or provide an explicit UI build command"),
        ),
        binding_baseline_doctor_check(),
        sdk_headers_doctor_check(),
        validator_doctor_check(),
        system_webview_check(),
    ];
    checks.extend(signing_doctor_checks());
    checks.extend(daw_install_checks());
    DoctorReport {
        os: Some(doctor_os_label().to_string()),
        ci_run_url: github_actions_run_url_from_env(),
        checks,
    }
}

fn doctor_os_label() -> &'static str {
    if cfg!(target_os = "linux") {
        "Linux"
    } else if cfg!(target_os = "macos") {
        "macOS"
    } else if cfg!(target_os = "windows") {
        "Windows"
    } else {
        "unknown"
    }
}

fn github_actions_run_url_from_env() -> Option<String> {
    let server = std::env::var("GITHUB_SERVER_URL").ok()?;
    let repo = std::env::var("GITHUB_REPOSITORY").ok()?;
    let run_id = std::env::var("GITHUB_RUN_ID").ok()?;
    if server.trim_end_matches('/') != "https://github.com"
        || repo.split('/').count() != 2
        || repo.split('/').any(str::is_empty)
        || !run_id.chars().all(|ch| ch.is_ascii_digit())
    {
        return None;
    }

    let mut url = format!(
        "{}/{}/actions/runs/{}",
        server.trim_end_matches('/'),
        repo,
        run_id
    );
    if let Ok(attempt) = std::env::var("GITHUB_RUN_ATTEMPT")
        && !attempt.is_empty()
        && attempt.chars().all(|ch| ch.is_ascii_digit())
    {
        url.push_str("/attempts/");
        url.push_str(&attempt);
    }
    Some(url)
}

fn command_check(command: &str, missing_hint: Option<&str>) -> DoctorCheck {
    let value = command_version(command);
    let found = value != "not found";
    DoctorCheck {
        name: command.to_string(),
        status: if found { "ok" } else { "missing" }.to_string(),
        value,
        hint: (!found)
            .then(|| missing_hint.unwrap_or("install this command and make sure it is on PATH"))
            .map(str::to_string),
    }
}

fn command_presence_check(
    name: &str,
    binary: &str,
    candidates: &[Utf8PathBuf],
    missing_hint: &str,
) -> DoctorCheck {
    match find_command(binary, candidates) {
        Some(path) => DoctorCheck {
            name: name.to_string(),
            status: "ok".to_string(),
            value: path.to_string(),
            hint: None,
        },
        None => DoctorCheck {
            name: name.to_string(),
            status: "missing".to_string(),
            value: format!("{binary} not found"),
            hint: Some(missing_hint.to_string()),
        },
    }
}

fn binding_baseline_doctor_check() -> DoctorCheck {
    DoctorCheck {
        name: "vst3 binding baseline".to_string(),
        status: "ok".to_string(),
        value: binding_baseline_value(),
        hint: binding_baseline_hint(),
    }
}

fn binding_baseline_value() -> String {
    let baseline = vesty_vst3_sys::BINDING_BASELINE;
    format!(
        "Steinberg SDK {}; upstream vst3 crate {}; backend {}",
        baseline.steinberg_sdk,
        baseline.upstream_vst3_crate,
        binding_backend_text(baseline.backend)
    )
}

fn binding_backend_text(backend: vesty_vst3_sys::BindingBackend) -> &'static str {
    match backend {
        vesty_vst3_sys::BindingBackend::UpstreamVst3Crate => "upstream-vst3",
        vesty_vst3_sys::BindingBackend::GeneratedHeadersReserved => "generated-headers-reserved",
        vesty_vst3_sys::BindingBackend::MetadataOnly => "metadata-only",
    }
}

fn binding_baseline_hint() -> Option<String> {
    (vesty_vst3_sys::BINDING_BASELINE.backend
        == vesty_vst3_sys::BindingBackend::GeneratedHeadersReserved)
        .then(|| {
            format!(
                "set {} to the official VST3 SDK checkout before generating header bindings",
                vesty_vst3_sys::VST3_SDK_DIR_ENV
            )
        })
}

fn sdk_headers_doctor_check() -> DoctorCheck {
    match vesty_vst3_sys::probe_sdk_headers_from_env() {
        Ok(probe) if probe.ready_for_generated_headers() => DoctorCheck {
            name: "vst3 SDK headers".to_string(),
            status: "ok".to_string(),
            value: sdk_header_probe_value(&probe),
            hint: None,
        },
        Ok(probe) => DoctorCheck {
            name: "vst3 SDK headers".to_string(),
            status: "missing".to_string(),
            value: sdk_header_probe_value(&probe),
            hint: Some(format!(
                "point {} at an official Steinberg VST3 SDK {} checkout before enabling generated header bindings",
                vesty_vst3_sys::VST3_SDK_DIR_ENV,
                vesty_vst3_sys::STEINBERG_VST3_SDK_BASELINE
            )),
        },
        Err(vesty_vst3_sys::SdkHeaderProbeError::MissingEnv) => DoctorCheck {
            name: "vst3 SDK headers".to_string(),
            status: "skipped".to_string(),
            value: format!(
                "{} is not set; upstream vst3 crate backend is active",
                vesty_vst3_sys::VST3_SDK_DIR_ENV
            ),
            hint: Some(format!(
                "set {} to the official Steinberg VST3 SDK checkout when generating Vesty-owned header bindings",
                vesty_vst3_sys::VST3_SDK_DIR_ENV
            )),
        },
    }
}

fn sdk_header_probe_value(probe: &vesty_vst3_sys::SdkHeaderProbe) -> String {
    let version_hint = probe
        .version_hint
        .as_deref()
        .unwrap_or("version marker not found");
    if probe.ready_for_generated_headers() {
        format!(
            "{}; {} required headers present; baseline {}; {}",
            probe.root.display(),
            probe.present_headers.len(),
            probe.baseline,
            version_hint
        )
    } else {
        format!(
            "{}; missing {}/{} required headers: {}; baseline {}; {}",
            probe.root.display(),
            probe.missing_headers.len(),
            vesty_vst3_sys::REQUIRED_GENERATED_HEADER_INPUTS.len(),
            probe.missing_headers.join(", "),
            probe.baseline,
            version_hint
        )
    }
}

fn validator_doctor_check() -> DoctorCheck {
    match discover_validator(None) {
        Some(path) => DoctorCheck {
            name: "vst3 validator".to_string(),
            status: "ok".to_string(),
            value: path.to_string(),
            hint: None,
        },
        None => DoctorCheck {
            name: "vst3 validator".to_string(),
            status: "missing".to_string(),
            value: "not found (set VST3_VALIDATOR or pass --validator)".to_string(),
            hint: Some(
                "build Steinberg VST3 SDK validator and expose it through VST3_VALIDATOR or PATH"
                    .to_string(),
            ),
        },
    }
}

fn signing_doctor_checks() -> Vec<DoctorCheck> {
    if cfg!(target_os = "macos") {
        vec![
            command_presence_check(
                "signing: codesign",
                "codesign",
                &[Utf8PathBuf::from("/usr/bin/codesign")],
                "install Xcode Command Line Tools before signing release bundles",
            ),
            macos_notarytool_check(),
        ]
    } else if cfg!(target_os = "windows") {
        vec![command_presence_check(
            "signing: signtool",
            "signtool.exe",
            &windows_signtool_candidates(),
            "install Windows SDK signtool.exe before signing release bundles",
        )]
    } else if cfg!(target_os = "linux") {
        vec![DoctorCheck {
            name: "signing: linux release policy".to_string(),
            status: "unknown".to_string(),
            value: "no standard VST3 bundle signing tool required by Vesty".to_string(),
            hint: Some(
                "sign distro packages or installers outside Vesty when your release channel requires it"
                    .to_string(),
            ),
        }]
    } else {
        vec![DoctorCheck {
            name: "signing: release signing".to_string(),
            status: "unsupported".to_string(),
            value: "unsupported platform".to_string(),
            hint: Some("Vesty MVP release packaging targets macOS, Windows and Linux".to_string()),
        }]
    }
}

fn macos_notarytool_check() -> DoctorCheck {
    let xcrun = find_command("xcrun", &[Utf8PathBuf::from("/usr/bin/xcrun")]);
    let Some(xcrun) = xcrun else {
        return DoctorCheck {
            name: "signing: notarytool".to_string(),
            status: "missing".to_string(),
            value: "xcrun not found".to_string(),
            hint: Some(
                "install Xcode Command Line Tools; notarization requires xcrun notarytool"
                    .to_string(),
            ),
        };
    };

    let output = Command::new(xcrun.as_std_path())
        .args(["--find", "notarytool"])
        .output();
    match output {
        Ok(output) if output.status.success() => {
            let value = String::from_utf8_lossy(&output.stdout).trim().to_string();
            DoctorCheck {
                name: "signing: notarytool".to_string(),
                status: "ok".to_string(),
                value: if value.is_empty() {
                    "notarytool found".to_string()
                } else {
                    value
                },
                hint: None,
            }
        }
        _ => DoctorCheck {
            name: "signing: notarytool".to_string(),
            status: "missing".to_string(),
            value: "notarytool not found via xcrun".to_string(),
            hint: Some(
                "install a recent Xcode or Command Line Tools before notarizing macOS bundles"
                    .to_string(),
            ),
        },
    }
}

fn system_webview_check() -> DoctorCheck {
    if cfg!(target_os = "macos") {
        let found = std::path::Path::new("/System/Library/Frameworks/WebKit.framework").exists();
        DoctorCheck {
            name: "system webview".to_string(),
            status: if found { "ok" } else { "missing" }.to_string(),
            value: if found {
                "ok (macOS WebKit.framework)".to_string()
            } else {
                "missing WebKit.framework".to_string()
            },
            hint: (!found).then(|| "install or repair macOS WebKit.framework".to_string()),
        }
    } else if cfg!(target_os = "windows") {
        let found = std::env::var_os("WEBVIEW2_BROWSER_EXECUTABLE_FOLDER").is_some()
            || std::path::Path::new(r"C:\Program Files (x86)\Microsoft\EdgeWebView\Application")
                .exists()
            || std::path::Path::new(r"C:\Program Files\Microsoft\EdgeWebView\Application").exists();
        DoctorCheck {
            name: "system webview".to_string(),
            status: if found { "ok" } else { "unknown" }.to_string(),
            value: if found {
                "ok (WebView2 runtime detected)".to_string()
            } else {
                "unknown (install Microsoft Edge WebView2 Runtime if host UI fails)".to_string()
            },
            hint: (!found).then(|| "install Microsoft Edge WebView2 Evergreen Runtime".to_string()),
        }
    } else if cfg!(target_os = "linux") {
        let webkit = pkg_config_version("webkit2gtk-4.1")
            .or_else(|| pkg_config_version("webkit2gtk-4.0"))
            .unwrap_or_else(|| "not found".to_string());
        let x11 = pkg_config_version("x11").unwrap_or_else(|| "not found".to_string());
        let found = webkit != "not found" && x11 != "not found";
        DoctorCheck {
            name: "system webview".to_string(),
            status: if found { "ok" } else { "missing" }.to_string(),
            value: format!("WebKitGTK {webkit}; X11 {x11}; Wayland experimental"),
            hint: (!found).then(|| {
                "install WebKitGTK 4.1/4.0, GTK3 and X11 development packages".to_string()
            }),
        }
    } else {
        DoctorCheck {
            name: "system webview".to_string(),
            status: "unsupported".to_string(),
            value: "unsupported platform".to_string(),
            hint: Some("Vesty MVP supports macOS, Windows and Linux X11".to_string()),
        }
    }
}

fn daw_install_checks() -> Vec<DoctorCheck> {
    DOCTOR_DAW_HOSTS
        .into_iter()
        .map(|host| {
            let candidates = match host {
                "REAPER" => daw_reaper_candidates(),
                "Cubase/Nuendo" => daw_cubase_nuendo_candidates(),
                "Bitwig Studio" => daw_bitwig_candidates(),
                "Ableton Live" => daw_ableton_candidates(),
                "Studio One" => daw_studio_one_candidates(),
                _ => Vec::new(),
            };
            daw_install_check(host, candidates)
        })
        .collect()
}

fn daw_install_check(host: &str, candidates: Vec<Utf8PathBuf>) -> DoctorCheck {
    match first_existing_path(&candidates) {
        Some(path) => DoctorCheck {
            name: format!("daw install: {host}"),
            status: "ok".to_string(),
            value: path.to_string(),
            hint: Some(
                "installation detected; real DAW smoke evidence is still required".to_string(),
            ),
        },
        None => DoctorCheck {
            name: format!("daw install: {host}"),
            status: "missing".to_string(),
            value: "not found in common install paths".to_string(),
            hint: Some(
                "optional for development; required only when collecting the release DAW matrix"
                    .to_string(),
            ),
        },
    }
}

fn first_existing_path(candidates: &[Utf8PathBuf]) -> Option<Utf8PathBuf> {
    candidates.iter().find(|path| path.exists()).cloned()
}

fn daw_reaper_candidates() -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    if cfg!(target_os = "macos") {
        candidates.extend(mac_app_candidates(["REAPER"]));
    } else if cfg!(target_os = "windows") {
        candidates.extend(windows_program_candidates([
            "REAPER (x64)\\reaper.exe",
            "REAPER\\reaper.exe",
        ]));
    } else if cfg!(target_os = "linux") {
        candidates.extend([
            Utf8PathBuf::from("/usr/bin/reaper"),
            Utf8PathBuf::from("/usr/local/bin/reaper"),
            Utf8PathBuf::from("/opt/REAPER/reaper"),
        ]);
    }
    candidates
}

fn daw_cubase_nuendo_candidates() -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    if cfg!(target_os = "macos") {
        candidates.extend(mac_app_prefix_candidates(["Cubase", "Nuendo"]));
    } else if cfg!(target_os = "windows") {
        candidates.extend(windows_program_prefix_candidates([
            ("Steinberg", "Cubase"),
            ("Steinberg", "Nuendo"),
        ]));
    }
    candidates
}

fn daw_bitwig_candidates() -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    if cfg!(target_os = "macos") {
        candidates.extend(mac_app_candidates(["Bitwig Studio"]));
    } else if cfg!(target_os = "windows") {
        candidates.extend(windows_program_candidates([
            "Bitwig Studio\\Bitwig Studio.exe",
        ]));
    } else if cfg!(target_os = "linux") {
        candidates.extend([
            Utf8PathBuf::from("/usr/bin/bitwig-studio"),
            Utf8PathBuf::from("/usr/local/bin/bitwig-studio"),
            Utf8PathBuf::from("/opt/bitwig-studio/bitwig-studio"),
            Utf8PathBuf::from("/opt/Bitwig Studio/bitwig-studio"),
        ]);
    }
    candidates
}

fn daw_ableton_candidates() -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    if cfg!(target_os = "macos") {
        candidates.extend(mac_app_prefix_candidates(["Ableton Live"]));
    } else if cfg!(target_os = "windows") {
        candidates.extend(windows_program_prefix_candidates([("Ableton", "Live")]));
    }
    candidates
}

fn daw_studio_one_candidates() -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    if cfg!(target_os = "macos") {
        candidates.extend(mac_app_prefix_candidates(["Studio One"]));
    } else if cfg!(target_os = "windows") {
        candidates.extend(windows_program_candidates([
            "PreSonus\\Studio One 6\\Studio One.exe",
        ]));
        candidates.extend(windows_program_prefix_candidates([(
            "PreSonus",
            "Studio One",
        )]));
    }
    candidates
}

fn mac_app_candidates<const N: usize>(names: [&str; N]) -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    for root in mac_application_roots() {
        for name in names {
            candidates.push(root.join(format!("{name}.app")));
        }
    }
    candidates
}

fn mac_app_prefix_candidates<const N: usize>(prefixes: [&str; N]) -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    for root in mac_application_roots() {
        if let Ok(entries) = fs::read_dir(root.as_std_path()) {
            for entry in entries.flatten() {
                let Ok(path) = Utf8PathBuf::from_path_buf(entry.path()) else {
                    continue;
                };
                let Some(name) = path.file_name() else {
                    continue;
                };
                if name.ends_with(".app") && prefixes.iter().any(|prefix| name.starts_with(prefix))
                {
                    candidates.push(path);
                }
            }
        }
    }
    candidates
}

fn mac_application_roots() -> Vec<Utf8PathBuf> {
    let mut roots = vec![Utf8PathBuf::from("/Applications")];
    if let Ok(home) = std::env::var("HOME") {
        roots.push(Utf8PathBuf::from(home).join("Applications"));
    }
    roots
}

fn windows_program_candidates<const N: usize>(relative_paths: [&str; N]) -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    for root in windows_program_roots() {
        for relative in relative_paths {
            candidates.push(root.join(relative));
        }
    }
    candidates
}

fn windows_program_prefix_candidates<const N: usize>(
    vendor_prefixes: [(&str, &str); N],
) -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    for root in windows_program_roots() {
        for (vendor, prefix) in vendor_prefixes {
            let vendor_dir = root.join(vendor);
            if let Ok(entries) = fs::read_dir(vendor_dir.as_std_path()) {
                for entry in entries.flatten() {
                    let Ok(path) = Utf8PathBuf::from_path_buf(entry.path()) else {
                        continue;
                    };
                    let Some(name) = path.file_name() else {
                        continue;
                    };
                    if name.starts_with(prefix) {
                        candidates.push(path);
                    }
                }
            }
        }
    }
    candidates
}

fn windows_program_roots() -> Vec<Utf8PathBuf> {
    ["ProgramFiles", "ProgramFiles(x86)", "ProgramW6432"]
        .into_iter()
        .filter_map(|var| std::env::var(var).ok())
        .map(Utf8PathBuf::from)
        .collect()
}

fn windows_signtool_candidates() -> Vec<Utf8PathBuf> {
    let mut candidates = Vec::new();
    for root in windows_program_roots() {
        let kit_bin = root.join("Windows Kits/10/bin");
        candidates.extend([
            kit_bin.join("x64/signtool.exe"),
            kit_bin.join("x86/signtool.exe"),
            kit_bin.join("arm64/signtool.exe"),
        ]);
        if let Ok(entries) = fs::read_dir(kit_bin.as_std_path()) {
            for entry in entries.flatten() {
                let Ok(version_dir) = Utf8PathBuf::from_path_buf(entry.path()) else {
                    continue;
                };
                candidates.extend([
                    version_dir.join("x64/signtool.exe"),
                    version_dir.join("x86/signtool.exe"),
                    version_dir.join("arm64/signtool.exe"),
                ]);
            }
        }
    }
    candidates
}

fn discover_validator(explicit: Option<Utf8PathBuf>) -> Option<Utf8PathBuf> {
    if let Some(path) = explicit {
        return Some(path);
    }
    if let Ok(path) = std::env::var("VST3_VALIDATOR") {
        let path = Utf8PathBuf::from(path);
        if path.is_file() {
            return Some(path);
        }
    }
    for name in validator_binary_names() {
        if let Some(path) = find_in_path(name) {
            return Some(path);
        }
    }
    validator_candidates()
        .into_iter()
        .find(|path| path.is_file())
}

fn validator_binary_names() -> &'static [&'static str] {
    if cfg!(target_os = "windows") {
        &["validator.exe", "validator"]
    } else {
        &["validator"]
    }
}

fn validator_candidates() -> Vec<Utf8PathBuf> {
    let mut roots = Vec::new();
    if let Ok(sdk) = std::env::var("VST3_SDK") {
        roots.push(Utf8PathBuf::from(sdk));
    }
    if let Ok(home) = std::env::var("HOME") {
        let home = Utf8PathBuf::from(home);
        roots.push(home.join("VST_SDK/VST3_SDK"));
        roots.push(home.join("SDKs/VST_SDK/VST3_SDK"));
        roots.push(home.join("Developer/VST3_SDK"));
    }
    if let Ok(profile) = std::env::var("USERPROFILE") {
        let profile = Utf8PathBuf::from(profile);
        roots.push(profile.join("VST_SDK/VST3_SDK"));
        roots.push(profile.join("source/VST3_SDK"));
    }

    let mut candidates = Vec::new();
    if let Ok(current_dir) = std::env::current_dir()
        && let Ok(current_dir) = Utf8PathBuf::from_path_buf(current_dir)
    {
        for name in validator_binary_names() {
            candidates.push(current_dir.join(format!(
                "target/steinberg/vst3sdk-build-xcode/bin/Release/{name}"
            )));
            candidates.push(
                current_dir.join(format!("target/steinberg/vst3sdk-build/bin/Release/{name}")),
            );
            candidates.push(current_dir.join(format!("target/steinberg/vst3sdk-build/bin/{name}")));
        }
    }
    for root in roots {
        for name in validator_binary_names() {
            candidates.push(root.join(format!("build/bin/{name}")));
            candidates.push(root.join(format!("build/bin/Debug/{name}")));
            candidates.push(root.join(format!("build/bin/Release/{name}")));
            candidates.push(root.join(format!("bin/{name}")));
        }
    }
    candidates
}

fn find_command(binary: &str, candidates: &[Utf8PathBuf]) -> Option<Utf8PathBuf> {
    find_in_path(binary).or_else(|| candidates.iter().find(|path| path.is_file()).cloned())
}

fn find_in_path(binary: &str) -> Option<Utf8PathBuf> {
    let path = std::env::var_os("PATH")?;
    for dir in std::env::split_paths(&path) {
        let candidate = dir.join(binary);
        if candidate.is_file()
            && let Ok(path) = Utf8PathBuf::from_path_buf(candidate)
        {
            return Some(path);
        }
    }
    None
}

fn pkg_config_version(package: &str) -> Option<String> {
    let output = Command::new("pkg-config")
        .args(["--modversion", package])
        .output()
        .ok()?;
    output
        .status
        .success()
        .then(|| String::from_utf8_lossy(&output.stdout).trim().to_string())
        .filter(|text| !text.is_empty())
}

fn build_configured_ui_assets(
    project_dir: &Utf8Path,
    ui: &UiConfig,
) -> Result<Option<AssetManifest>, Box<dyn std::error::Error>> {
    let ui_dir = project_dir.join(&ui.dir);
    if let Some(build) = &ui.build {
        run_ui_build_command(build, &ui_dir)?;
    }

    let Some(dist) = &ui.dist else {
        return Ok(None);
    };

    let root = ui_dir.join(dist);
    if !root.is_dir() {
        return Err(format!(
            "ui dist directory does not exist: {root}; check [ui].dist or run [ui].build"
        )
        .into());
    }
    let manifest = AssetManifest::from_dir(&root, "index.html").map_err(|error| {
        format!("failed to create UI asset manifest from [ui].dist {root}: {error}")
    })?;
    Ok(Some(manifest))
}

fn run_ui_build_command(
    command: &str,
    ui_dir: &Utf8PathBuf,
) -> Result<(), Box<dyn std::error::Error>> {
    if command.trim().is_empty() {
        return Err("[ui].build must not be empty".into());
    }
    if !ui_dir.is_dir() {
        return Err(format!("ui directory does not exist for [ui].build: {ui_dir}").into());
    }
    run_shell(command, Some(ui_dir))
        .map_err(|error| format!("[ui].build failed in {ui_dir}: `{command}`: {error}").into())
}

fn run_shell(command: &str, cwd: Option<&Utf8PathBuf>) -> Result<(), Box<dyn std::error::Error>> {
    if command.trim().is_empty() {
        return Err("shell command must not be empty".into());
    }
    let cwd_text = cwd.map(ToString::to_string);
    let mut shell = if cfg!(target_os = "windows") {
        let mut command_runner = Command::new("cmd");
        command_runner.args(["/C", command]);
        command_runner
    } else {
        let mut command_runner = Command::new("sh");
        command_runner.args(["-lc", command]);
        command_runner
    };
    if let Some(cwd) = cwd {
        if !cwd.is_dir() {
            return Err(format!("command working directory does not exist: {cwd}").into());
        }
        shell.current_dir(cwd);
    }
    let status = shell.status().map_err(|error| {
        let cwd_suffix = cwd_text
            .as_deref()
            .map(|cwd| format!(" in {cwd}"))
            .unwrap_or_default();
        format!("failed to run command{cwd_suffix}: `{command}`: {error}")
    })?;
    if status.success() {
        Ok(())
    } else {
        let cwd_suffix = cwd_text
            .as_deref()
            .map(|cwd| format!(" in {cwd}"))
            .unwrap_or_default();
        Err(format!("command failed with status {status}{cwd_suffix}: `{command}`").into())
    }
}

fn create_project(
    name: &str,
    kind: Option<&str>,
    ui: Option<&str>,
    template: Option<&str>,
    vesty_path: Option<&Utf8Path>,
    plugin_ui_path: Option<&Utf8Path>,
) -> Result<(), Box<dyn std::error::Error>> {
    let root = Utf8PathBuf::from(name);
    if path_exists_no_follow(&root)? {
        return Err(format!("project path already exists: {root}").into());
    }
    reject_existing_output_parent_symlink("project path", &root)?;
    let project_name = project_name_from_path(&root, name);
    let project_template = template.map(resolve_project_template).transpose()?;
    let kind = canonical_project_kind(
        kind.or_else(|| project_template.map(|template| template.kind))
            .unwrap_or("effect"),
    )?;
    let ui_template = parse_ui_template(
        ui.or_else(|| project_template.map(|template| template.ui))
            .unwrap_or("react"),
    )?;

    let crate_name = sanitize_crate_name(&project_name);
    let plugin_type = pascal_ident(&project_name);
    let params_type = format!("{plugin_type}Params");
    let kernel_type = format!("{plugin_type}Kernel");
    let class_id = class_id_from_name(&project_name);
    let class_id_toml = uuid_string(class_id);
    let class_id_rust = rust_byte_array(class_id);
    let is_instrument = kind == "instrument";
    let package_category = package_category_for_kind(kind);
    let bundle_id = format!("dev.vesty.{crate_name}");
    let with_ui = ui_template != UiTemplate::None;
    let ui_param = UiParamTemplate::for_kind(kind);
    let param_specs_json = default_param_specs_json(kind);
    let parameter_manifest = parameter_manifest_from_specs_json(param_specs_json)?;
    let local_vesty_path = vesty_path
        .map(|path| {
            Utf8PathBuf::from_path_buf(path.canonicalize()?).map_err(
                |_| -> Box<dyn std::error::Error> { "vesty path is not valid utf-8".into() },
            )
        })
        .transpose()?;
    let local_plugin_ui_path = plugin_ui_path
        .map(|path| {
            Utf8PathBuf::from_path_buf(path.canonicalize()?).map_err(
                |_| -> Box<dyn std::error::Error> {
                    "vesty-plugin-ui path is not valid utf-8".into()
                },
            )
        })
        .transpose()?;
    let ui_package_paths = UiPackagePaths::from_plugin_ui_path(local_plugin_ui_path.as_deref());

    fs::create_dir_all(root.join("src"))?;
    if with_ui {
        fs::create_dir_all(root.join("ui/src"))?;
    }
    require_existing_directory_no_symlink("project path", &root)?;
    let ui_config = if with_ui {
        r#"
[ui]
dir = "ui"
dev_url = "http://localhost:5173"
build = "npm run build"
dist = "dist"
width = 900
height = 560
min_width = 640
min_height = 420
"#
    } else {
        ""
    };
    fs::write(
        root.join("vesty.toml"),
        vesty_toml(
            &project_name,
            kind,
            &class_id_toml,
            ui_config,
            &bundle_id,
            package_category,
        ),
    )?;
    fs::write(
        root.join("Cargo.toml"),
        cargo_toml(&project_name, &crate_name, local_vesty_path.as_deref()),
    )?;
    fs::write(
        root.join("README.md"),
        project_readme(&project_name, kind, ui_template),
    )?;
    write_text_file(&root.join("params.specs.json"), param_specs_json)?;
    write_parameter_manifest(&root.join("vesty-parameters.json"), &parameter_manifest)?;
    let source = if is_instrument {
        instrument_template(
            &project_name,
            &plugin_type,
            &params_type,
            &kernel_type,
            &class_id_rust,
            with_ui,
        )
    } else {
        effect_template(
            &project_name,
            &plugin_type,
            &params_type,
            &kernel_type,
            &class_id_rust,
            with_ui,
        )
    };
    fs::write(root.join("src/lib.rs"), source)?;
    if with_ui {
        write_ui_template(
            &root,
            &project_name,
            ui_template,
            &ui_package_paths,
            ui_param,
        )?;
    }
    Ok(())
}

